import type { Address, PublicClient } from 'viem'
import { erc20Abi, erc4626Abi, pausableAbi } from '../constants/abis'
import type { VaultState } from '../types'

export async function getVaultState(
  publicClient: PublicClient,
  vaultAddress: Address,
): Promise<VaultState> {
  const [name, symbol, decimals, totalSupply, totalAssets, asset] = await Promise.all([
    publicClient.readContract({
      address: vaultAddress,
      abi: erc4626Abi,
      functionName: 'name',
    }),
    publicClient.readContract({
      address: vaultAddress,
      abi: erc4626Abi,
      functionName: 'symbol',
    }),
    publicClient.readContract({
      address: vaultAddress,
      abi: erc4626Abi,
      functionName: 'decimals',
    }),
    publicClient.readContract({
      address: vaultAddress,
      abi: erc4626Abi,
      functionName: 'totalSupply',
    }),
    publicClient.readContract({
      address: vaultAddress,
      abi: erc4626Abi,
      functionName: 'totalAssets',
    }),
    publicClient.readContract({
      address: vaultAddress,
      abi: erc4626Abi,
      functionName: 'asset',
    }),
  ])

  const assetDecimals = await publicClient.readContract({
    address: asset,
    abi: erc20Abi,
    functionName: 'decimals',
  })

  const exchangeRate =
    totalSupply > 0n
      ? await publicClient.readContract({
          address: vaultAddress,
          abi: erc4626Abi,
          functionName: 'convertToAssets',
          args: [10n ** BigInt(decimals)],
        })
      : 10n ** BigInt(assetDecimals)

  return {
    address: vaultAddress,
    name,
    symbol,
    decimals,
    totalAssets,
    totalSupply,
    asset,
    assetDecimals,
    exchangeRate,
  }
}

export async function previewDeposit(
  publicClient: PublicClient,
  vaultAddress: Address,
  assets: bigint,
): Promise<bigint> {
  return publicClient.readContract({
    address: vaultAddress,
    abi: erc4626Abi,
    functionName: 'previewDeposit',
    args: [assets],
  })
}

