import type { Address } from 'viem'
import type { ApiClient } from './client'
import type {
  ApiResponse,
  DailyAllocationSnapshot,
  FormattedValue,
  GlobalVaultHistoryResponse,
  Network,
  PerformanceBenchmark,
  RawTvlTimeseriesPoint,
  RawYieldTimeseriesPoint,
  SharePriceHistoryPoint,
  TimeseriesPoint,
  TotalTvlTimeseriesPoint,
  VaultActivityFilters,
  VaultHistoryResponse,
  VaultPercentile,
  VaultPerformance,
  VaultSnapshot,
  VaultStatsItem,
} from './types'

// Convert milliseconds to seconds if needed (threshold: year 2100 in seconds)
function normalizeTimestamp(ts: number): number {
  return ts > 4102444800 ? Math.floor(ts / 1000) : ts
}

export async function getVaultSnapshot(
  client: ApiClient,
  network: Network,
  vaultAddress: Address,
): Promise<VaultSnapshot> {
  const response = await client.fetch<ApiResponse<VaultSnapshot>>(
    `/api/v1/vault/${network}/${vaultAddress}`,
  )
  return response.data
}

