export async function getVaultYieldTimeseries(
  client: ApiClient,
  network: Network,
  vaultAddress: Address,
): Promise<TimeseriesPoint[]> {
  const response = await client.fetch<ApiResponse<RawYieldTimeseriesPoint[]>>(
    `/api/v1/vault/yield/timeseries/${network}/${vaultAddress}`,
  )
  return response.data.map((point) => ({
    timestamp: normalizeTimestamp(point.timestamp),
    value: parseFloat(point.yield) / 100, // Convert percentage to decimal
  }))
}

export async function getVaultTvlTimeseries(
  client: ApiClient,
  network: Network,
  vaultAddress: Address,
): Promise<TimeseriesPoint[]> {
  const response = await client.fetch<ApiResponse<RawTvlTimeseriesPoint[]>>(
    `/api/v1/vault/tvl/timeseries/${network}/${vaultAddress}`,
  )
  return response.data.map((point) => ({
    timestamp: normalizeTimestamp(point.timestamp),
    value: parseFloat(point.tvl),
  }))
}

