export async function getVaultHistoryAllNetworks(
  client: ApiClient,
  vaultAddress: Address,
  options?: { cursor?: number; limit?: number; filters?: VaultActivityFilters },
): Promise<GlobalVaultHistoryResponse> {
  const endpoint = client.buildUrl('/api/v1/history/vaults', {
    vaultAddress,
    cursor: options?.cursor,
    limit: options?.limit,
    whale: options?.filters?.whale,
    type: options?.filters?.type,
    period: options?.filters?.period,
    network: options?.filters?.network,
  })
  const response = await client.fetch<ApiResponse<GlobalVaultHistoryResponse>>(endpoint)
  return response.data
}

/**
 * Fetch deposit/withdrawal history across ALL vaults and networks.
 * Uses the global /api/v1/history/vaults endpoint (single API call).
 */
export async function getGlobalVaultHistory(
  client: ApiClient,
  options?: { cursor?: number; limit?: number; filters?: VaultActivityFilters },
): Promise<GlobalVaultHistoryResponse> {
  const endpoint = client.buildUrl('/api/v1/history/vaults', {
    cursor: options?.cursor,
    limit: options?.limit,
    whale: options?.filters?.whale,
    type: options?.filters?.type,
    period: options?.filters?.period,
    network: options?.filters?.network,
  })
  const response = await client.fetch<ApiResponse<GlobalVaultHistoryResponse>>(endpoint)
  return response.data
}

