import type { Address, PublicClient } from 'viem'
import { getTokenAllowance, hasEnoughAllowance } from '../reads/allowance'
import { getShareBalance, getTokenBalance, getUserVaultPosition } from '../reads/balance'
import type { TokenAllowance, TokenBalance, UserVaultPosition } from '../types'

export class UserReadService {
  constructor(private readonly publicClient: PublicClient) {}

  getTokenBalance(token: Address, account: Address): Promise<TokenBalance> {
    return getTokenBalance(this.publicClient, token, account)
  }

  getShareBalance(vaultAddress: Address, account: Address): Promise<bigint> {
    return getShareBalance(this.publicClient, vaultAddress, account)
  }

  getUserPosition(vaultAddress: Address, account: Address): Promise<UserVaultPosition> {
    return getUserVaultPosition(this.publicClient, vaultAddress, account)
  }

  getAllowance(token: Address, owner: Address, spender: Address): Promise<TokenAllowance> {
    return getTokenAllowance(this.publicClient, token, owner, spender)
  }

  hasEnoughAllowance(
    token: Address,
    owner: Address,
    spender: Address,
    amount: bigint,
  ): Promise<boolean> {
    return hasEnoughAllowance(this.publicClient, token, owner, spender, amount)
  }
}
