import type { Hash, PublicClient, WalletClient } from 'viem'
import { decodeEventLog } from 'viem'
import { erc20Abi, yoGatewayAbi } from '../constants/abis'
import { YO_GATEWAY_ADDRESS } from '../constants/addresses'
import type { RedeemParams, RedeemReceipt, RedeemResult, RedeemWithApprovalResult } from '../types'
import { applySlippage } from '../utils/math'
import { validateAddress, validateAmount } from '../utils/validation'

export interface RedeemViaGatewayParams extends RedeemParams {
  partnerId?: number
}

export async function redeem(
  walletClient: WalletClient,
  publicClient: PublicClient,
  params: RedeemViaGatewayParams,
): Promise<RedeemResult> {
  const { vault, shares, recipient, slippageBps = 50, partnerId = 9999 } = params

  validateAddress(vault, 'vault')
  validateAmount(shares, 'shares')

  const account = walletClient.account
  if (!account) {
    throw new Error('Wallet client must have an account')
  }

  const receiver = recipient ?? account.address

  const expectedAssets = await publicClient.readContract({
    address: YO_GATEWAY_ADDRESS,
    abi: yoGatewayAbi,
    functionName: 'quotePreviewRedeem',
    args: [vault, shares],
  })

  const minAssetsOut = params.minAssetsOut ?? applySlippage(expectedAssets, slippageBps)

  const { request } = await publicClient.simulateContract({
    address: YO_GATEWAY_ADDRESS,
    abi: yoGatewayAbi,
    functionName: 'redeem',
    args: [vault, shares, minAssetsOut, receiver, partnerId],
    account,
  })

  const hash = await walletClient.writeContract(request)

  return {
    hash,
    assets: expectedAssets,
  }
}

export async function redeemWithApproval(
  walletClient: WalletClient,
  publicClient: PublicClient,
  params: RedeemViaGatewayParams,
): Promise<RedeemWithApprovalResult> {
  const { vault, shares } = params

  const account = walletClient.account
  if (!account) {
    throw new Error('Wallet client must have an account')
  }

  const allowance = await publicClient.readContract({
    address: vault,
    abi: erc20Abi,
    functionName: 'allowance',
    args: [account.address, YO_GATEWAY_ADDRESS],
  })

  let approveHash: `0x${string}` | undefined

  if (allowance < shares) {
    approveHash = await walletClient.writeContract({
      address: vault,
      abi: erc20Abi,
      functionName: 'approve',
      args: [YO_GATEWAY_ADDRESS, shares],
      account,
      chain: walletClient.chain,
    })

    await publicClient.waitForTransactionReceipt({ hash: approveHash })
  }

  const result = await redeem(walletClient, publicClient, params)

  return {
    approveHash,
    redeemHash: result.hash,
    assets: result.assets,
  }
}

export async function waitForRedeemReceipt(
  publicClient: PublicClient,
  hash: Hash,
): Promise<RedeemReceipt> {
  const receipt = await publicClient.waitForTransactionReceipt({ hash })

  for (const log of receipt.logs) {
    try {
      const event = decodeEventLog({
        abi: yoGatewayAbi,
        data: log.data,
        topics: log.topics,
      })

      if (event.eventName === 'YoGatewayRedeem') {
        const args = event.args as {
          shares: bigint
          assetsOrRequestId: bigint
          instant: boolean
        }
        return {
          hash,
          status: receipt.status,
          instant: args.instant,
          assetsOrRequestId: args.assetsOrRequestId,
          shares: args.shares,
          blockNumber: receipt.blockNumber,
        }
      }
    } catch {
      // Not a matching event, continue
    }
  }

  throw new Error(
    `YoGatewayRedeem event not found in transaction ${hash}. The transaction may have succeeded but the event could not be decoded.`,
  )
}
