export function getVaultByAddress(address: Address): VaultConfig | undefined {
  const normalizedAddress = address.toLowerCase()
  return Object.values(VAULTS).find((v) => v.address.toLowerCase() === normalizedAddress)
}

export function getVaultsForChain(chainId: number): VaultConfig[] {
  return Object.values(VAULTS).filter((v) => v.chains.includes(chainId))
}

export function getAllVaults(): VaultConfig[] {
  return Object.values(VAULTS)
}
