import type { Address } from 'viem'
import { getAddress } from 'viem'
import { base } from 'viem/chains'
import {
  MERKL_API_BASE_URL,
  MERKL_CREATOR_ADDRESS,
  type MerklCampaignStatus,
  YO_TOKEN,
} from '../constants/merkl'
import { VAULTS } from '../constants/addresses'
import type { MerklCampaign, MerklChainRewards, MerklPendingRewards, MerklTokenReward } from '../types'

export interface MerklApiClientConfig {
  baseUrl?: string
}

export class MerklApiClient {
  private baseUrl: string

  constructor(config?: MerklApiClientConfig) {
    this.baseUrl = config?.baseUrl ?? MERKL_API_BASE_URL
  }

  private async fetch<T>(endpoint: string, params?: Record<string, unknown>): Promise<T> {
    const url = new URL(`${this.baseUrl}${endpoint}`)

    if (params) {
      for (const [key, value] of Object.entries(params)) {
        if (value !== undefined && value !== null) {
          url.searchParams.append(key, String(value))
        }
      }
    }

    const response = await fetch(url.toString(), {
      headers: {
        Accept: 'application/json',
      },
    })

    if (!response.ok) {
      throw new Error(`Merkl API request failed: ${response.statusText}`)
    }

    return response.json()
  }

  async getCampaigns(options?: {
    status?: MerklCampaignStatus
    creatorAddress?: string
  }): Promise<MerklCampaign[]> {
    const PAGE_SIZE = 50
    let page = 0
    const allCampaigns: MerklCampaign[] = []

    while (true) {
      const params: Record<string, unknown> = {
        creatorAddress: options?.creatorAddress ?? MERKL_CREATOR_ADDRESS,
        withOpportunity: true,
        items: PAGE_SIZE,
        page,
      }

      if (options?.status) {
        params.status = options.status
      }

      const campaigns = await this.fetch<MerklCampaign[]>('/campaigns', params)
      allCampaigns.push(...campaigns)

      if (campaigns.length < PAGE_SIZE) {
        break
      }

      page++
    }

    return allCampaigns
  }

  async getUserRewards(
    userAddress: Address,
    chainId: number = base.id,
  ): Promise<MerklChainRewards | null> {
    const params = {
      chainIds: chainId,
      reloadChainId: chainId,
    }

    const rewards = await this.fetch<MerklChainRewards[]>(
      `/users/${userAddress}/rewards/breakdowns`,
      params,
    )

    const chainRewards = rewards[0]
    if (!chainRewards) return null

    // Filter to only YO token rewards
    const yoRewards = chainRewards.rewards.filter(
      (reward) => getAddress(reward.token.address) === getAddress(YO_TOKEN.address),
    )

    if (yoRewards.length === 0) return null

    return { ...chainRewards, rewards: yoRewards }
  }
}

export function createMerklApiClient(config?: MerklApiClientConfig): MerklApiClient {
  return new MerklApiClient(config)
}

// Utility functions

export function getClaimableAmount(reward: MerklTokenReward): bigint {
  const amount = BigInt(reward.amount)
  const claimed = BigInt(reward.claimed)
  return amount > claimed ? amount - claimed : 0n
}

export function hasClaimableRewards(chainRewards: MerklChainRewards): boolean {
  return chainRewards.rewards.some((reward) => getClaimableAmount(reward) > 0n)
}

export function prepareClaimParams(
  userAddress: Address,
  chainRewards: MerklChainRewards,
): {
  users: Address[]
  tokens: Address[]
  amounts: bigint[]
  proofs: `0x${string}`[][]
} {
  const users: Address[] = []
  const tokens: Address[] = []
  const amounts: bigint[] = []
  const proofs: `0x${string}`[][] = []

  for (const reward of chainRewards.rewards) {
    const claimable = getClaimableAmount(reward)

    if (claimable > 0n && reward.proofs && reward.proofs.length > 0) {
      users.push(userAddress)
      tokens.push(getAddress(reward.token.address))
      amounts.push(BigInt(reward.amount)) // Use full amount for proof verification
      proofs.push(reward.proofs as `0x${string}`[])
    }
  }

  return { users, tokens, amounts, proofs }
}

export function getTotalClaimable(chainRewards: MerklChainRewards): bigint {
  return chainRewards.rewards.reduce((total, reward) => total + getClaimableAmount(reward), 0n)
}

/** Set of all known yo vault addresses (lowercased) for primary vault matching */
const VAULT_ADDRESSES = new Set(Object.values(VAULTS).map((v) => v.address.toLowerCase()))

/** Reverse mapping: vault address → vault symbol (e.g. "yoETH") */
const VAULT_ADDRESS_TO_SYMBOL = new Map(
  Object.values(VAULTS).map((v) => [v.address.toLowerCase(), v.symbol]),
)

/** Token symbol patterns for vault type matching */
const VAULT_ASSET_PATTERNS: Record<string, RegExp> = {
  yoETH: /yoETH|^ETH$|WETH|stETH|wstETH|cbETH|rETH|weETH|frxETH|oETH/i,
  yoUSD: /yoUSD|^USD$|USDC|USDT|DAI|USDS|gtUSDC/i,
  yoEUR: /yoEUR|^EUR$|EURC/i,
  yoBTC: /yoBTC|^BTC$|WBTC|cbBTC|LBTC/i,
  yoGOLD: /yoGOLD|^GOLD$|XAUT/i,
}

/**
 * Determine which yo vault type an opportunity belongs to.
 * Matches by vault address first, then by token symbol patterns.
 */
function resolveVaultType(opportunity: { identifier?: string; tokens?: Array<{ address: string; symbol: string }> }): string | null {
  if (opportunity.identifier) {
    const match = VAULT_ADDRESS_TO_SYMBOL.get(opportunity.identifier.toLowerCase())
    if (match) return match
  }
  const tokens = opportunity.tokens ?? []
  for (const token of tokens) {
    const match = VAULT_ADDRESS_TO_SYMBOL.get(token.address.toLowerCase())
    if (match) return match
  }
  for (const token of tokens) {
    for (const [vaultName, pattern] of Object.entries(VAULT_ASSET_PATTERNS)) {
      if (pattern.test(token.symbol)) return vaultName
    }
  }
  return null
}

/**
 * Extract sets of opportunity IDs and vault types that have pending (claimable) rewards.
 *
 * Primary yo vault campaigns are matched by vault type (for cross-chain reward matching).
 * All other campaigns are matched by exact opportunity ID.
 *
 * Usage:
 * ```ts
 * const rewards = await client.getClaimableRewards(userAddress)
 * const pending = getPendingRewardSets(rewards)
 *
 * // Check if a campaign has pending rewards:
 * const isPrimary = VAULT_ADDRESSES.has(campaign.Opportunity.identifier)
 * const hasPending = isPrimary
 *   ? pending.vaultTypes.has(getVaultType(campaign.Opportunity))
 *   : pending.opportunityIds.has(campaign.Opportunity.id)
 * ```
 */
export function getPendingRewardSets(chainRewards: MerklChainRewards | null): MerklPendingRewards {
  const opportunityIds = new Set<string>()
  const vaultTypes = new Set<string>()

  if (!chainRewards?.rewards) return { opportunityIds, vaultTypes }

  for (const reward of chainRewards.rewards) {
    if (!reward.breakdowns) continue
    for (const breakdown of reward.breakdowns) {
      const claimable = BigInt(breakdown.amount) - BigInt(breakdown.claimed)
      if (claimable <= 0n) continue

      if (breakdown.opportunity?.id) {
        opportunityIds.add(breakdown.opportunity.id)
      }
      const vt = resolveVaultType(breakdown.opportunity)
      if (vt) {
        vaultTypes.add(vt)
      }
    }
  }

  return { opportunityIds, vaultTypes }
}

/**
 * Check whether a specific campaign has pending rewards for the user.
 *
 * Primary yo vault campaigns are matched by vault type (cross-chain).
 * Other campaigns are matched by exact opportunity ID.
 */
export function campaignHasPendingRewards(
  campaign: MerklCampaign,
  pendingRewards: MerklPendingRewards,
): boolean {
  const opp = campaign.Opportunity
  if (!opp) return false

  const isPrimaryYoVault = opp.identifier && VAULT_ADDRESSES.has(opp.identifier.toLowerCase())

  if (isPrimaryYoVault) {
    return pendingRewards.vaultTypes.has(resolveVaultType(opp) ?? '')
  }
  return pendingRewards.opportunityIds.has(opp.id ?? '')
}
