import type { Address, PublicClient } from 'viem'
import { yoGatewayAbi } from '../constants/abis'
import { YO_GATEWAY_ADDRESS } from '../constants/addresses'

export async function quotePreviewDeposit(
  publicClient: PublicClient,
  vaultAddress: Address,
  assets: bigint,
): Promise<bigint> {
  return publicClient.readContract({
    address: YO_GATEWAY_ADDRESS,
    abi: yoGatewayAbi,
    functionName: 'quotePreviewDeposit',
    args: [vaultAddress, assets],
  })
}

