import { encodeFunctionData } from 'viem'
import { base } from 'viem/chains'
import { MERKL_DISTRIBUTOR_ADDRESSES } from '../constants/merkl'
import { merklDistributorAbi } from '../constants/merkl-abi'
import type { ClaimMerklRewardsParams, PreparedTransaction } from '../types'

export function prepareClaimMerklRewards(
  params: ClaimMerklRewardsParams,
): PreparedTransaction {
  const distributorAddress = MERKL_DISTRIBUTOR_ADDRESSES[base.id]

  if (!distributorAddress) {
    throw new Error('No Merkl distributor found for Base')
  }

  const { users, tokens, amounts, proofs } = params

  if (users.length === 0) {
    throw new Error('No rewards to claim')
  }

  const data = encodeFunctionData({
    abi: merklDistributorAbi,
    functionName: 'claim',
    args: [users, tokens, amounts, proofs],
  })

  return { to: distributorAddress, data, value: 0n, chainId: base.id }
}
