import type { Address, PublicClient } from 'viem'
import { base } from 'viem/chains'
import { prepareClaimMerklRewards } from '../actions/merkl'
import {
  getClaimableAmount,
  getPendingRewardSets,
  getTotalClaimable,
  hasClaimableRewards,
  type MerklApiClient,
  prepareClaimParams,
} from '../api/merkl'
import type { MerklCampaignStatus } from '../constants/merkl'
import { getClaimedAmount, getClaimedAmounts } from '../reads/merkl'
import type {
  MerklCampaign,
  MerklChainRewards,
  MerklPendingRewards,
  MerklTokenReward,
  PreparedTransaction,
} from '../types'
import type { SupportedChainId } from '../constants/chains'

export class MerklService {
  /** Rewards are always distributed on Base — use the Base public client for on-chain reads */
  private readonly basePublicClient: PublicClient

  constructor(
    publicClients: Record<SupportedChainId, PublicClient>,
    private readonly merklApiClient: MerklApiClient,
  ) {
    this.basePublicClient = publicClients[base.id as SupportedChainId]
  }

  // API

  getCampaigns(options?: { status?: MerklCampaignStatus }): Promise<MerklCampaign[]> {
    return this.merklApiClient.getCampaigns(options)
  }

  getRewards(user: Address): Promise<MerklChainRewards | null> {
    return this.merklApiClient.getUserRewards(user, base.id)
  }

  // On-chain

  getClaimedAmount(user: Address, token: Address): Promise<bigint> {
    return getClaimedAmount(this.basePublicClient, user, token, base.id)
  }

  // Hybrid

  async getClaimableRewards(user: Address): Promise<MerklChainRewards | null> {
    const apiRewards = await this.getRewards(user)
    if (!apiRewards || apiRewards.rewards.length === 0) return null

    const tokenAddresses = apiRewards.rewards.map((r) => r.token.address)
    const claimedMap = await getClaimedAmounts(
      this.basePublicClient,
      user,
      tokenAddresses,
      base.id,
    )

    return {
      ...apiRewards,
      rewards: apiRewards.rewards.map((reward) => ({
        ...reward,
        claimed: (claimedMap.get(reward.token.address) ?? 0n).toString(),
      })),
    }
  }

  // Prepare

  prepareClaimRewards(userAddress: Address, chainRewards: MerklChainRewards): PreparedTransaction {
    const claimParams = prepareClaimParams(userAddress, chainRewards)

    if (claimParams.users.length === 0) {
      throw new Error('No claimable rewards')
    }

    return prepareClaimMerklRewards(claimParams)
  }

  // Utilities

  getClaimableAmount(reward: MerklTokenReward): bigint {
    return getClaimableAmount(reward)
  }

  hasClaimableRewards(chainRewards: MerklChainRewards): boolean {
    return hasClaimableRewards(chainRewards)
  }

  getTotalClaimable(chainRewards: MerklChainRewards): bigint {
    return getTotalClaimable(chainRewards)
  }

  /**
   * Fetch claimable rewards and return which opportunities/vault types have pending rewards.
   * Use the result with `campaignHasPendingRewards()` to check individual campaigns.
   */
  async getPendingRewards(user: Address): Promise<MerklPendingRewards> {
    const rewards = await this.getClaimableRewards(user)
    return getPendingRewardSets(rewards)
  }

  getPendingRewardSets(chainRewards: MerklChainRewards | null): MerklPendingRewards {
    return getPendingRewardSets(chainRewards)
  }
}
